#include<bits/stdc++.h>
using namespace std;
struct node
{
    int val,id;
    bool operator<(const node&b)const
    {
        if(val==b.val)
        {
            return id<b.id;
        }
        return val>b.val;
    }
}a[200010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i].val);
            a[i].id=i;
        }
        sort(a+1,a+1+n);
        int max1=0,max2=0,flag=0;
        for(int i=1;i<=n;i++)
        {
            if(a[i].id>max1)
            {
                max2=max1;
                max1=a[i].id;
                printf("%d ",a[i].val);
            }
            else if(!flag&&a[i].id>max2)
            {
                flag=1;
                max1=a[i].id;
                printf("%d ",a[i].val);
            }
        }
        printf("\n");
    }
    return 0;
}
